module RefModule(a, b, q, clk);parameter width = 16, cycles=1; 
  input signed [width-1:0] a, b; 
  input clk; 
  output signed [width-1:0] q; 
  reg signed [width-1:0] res[cycles-1:0]; 
  assign q = res[cycles-1]; 
  integer obf_i; 
  always @(posedge clk) begin 
  res[0] <= a-b; 
  for (obf_i=1; obf_i < cycles; obf_i = obf_i+1) 
  res[obf_i] <= res[obf_i-1]; 
  end 
 endmodule
